// Aimfox sends the event payload as the POST body.
// n8n wraps it under `.body`; fall back to the root just in case.
const raw = $input.first().json;
const p = raw.body || raw;

const event = p.event || p.type || p.event_type || 'reply';

// Sender / lead name (Aimfox field names can vary by event, so we probe several)
const lead = p.lead || p.target || p.contact || p.from || {};
const name =
  lead.full_name ||
  [lead.first_name, lead.last_name].filter(Boolean).join(' ') ||
  p.full_name ||
  p.name ||
  'Unknown lead';

// Reply text
const message =
  (p.message && (p.message.text || p.message.body)) ||
  p.text ||
  p.body ||
  p.reply ||
  '';

const account = p.account_name || (p.account && p.account.full_name) || p.account_id || '';
const campaign = (p.campaign && p.campaign.name) || p.campaign_name || p.campaign_id || '';

const esc = (s) =>
  String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

let out = `🔔 <b>New LinkedIn reply</b>\n`;
out += `👤 <b>${esc(name)}</b>\n`;
if (campaign) out += `📣 ${esc(campaign)}\n`;
if (account) out += `🔗 via ${esc(account)}\n`;
if (message) out += `\n💬 ${esc(message)}\n`;
out += `\n<code>event: ${esc(event)}</code>`;

// If we couldn't locate the message text, attach the raw payload so nothing is lost.
// (First real reply lets us see the exact field names and make this pretty.)
if (!message) {
  out += `\n\n<b>Raw payload:</b>\n<pre>${esc(JSON.stringify(p).slice(0, 1500))}</pre>`;
}

return [{ json: { message: out, raw: p } }];
